'use client';

import AdminLayout from '@/components/AdminLayout';
import Link from 'next/link';
import { useState } from 'react';

type DevotionalStatus = 'all' | 'draft' | 'scheduled' | 'published';

export default function DevotionalsPage() {
    const [filter, setFilter] = useState<DevotionalStatus>('all');

    return (
        <AdminLayout>
            <div className="page-header">
                <div className="page-header-top">
                    <div>
                        <h1 className="page-title">Devotionals</h1>
                        <p className="page-subtitle">Manage your daily devotional content</p>
                    </div>
                    <div style={{ display: 'flex', gap: 10 }}>
                        <Link href="/templates" className="btn btn-secondary">
                            <span>📋</span> Templates
                        </Link>
                        <Link href="/devotionals/new" className="btn btn-primary">
                            <span>✏️</span> New Devotional
                        </Link>
                    </div>
                </div>
            </div>

            <div className="page-body">
                {/* Filter Tabs */}
                <div className="tabs">
                    {(['all', 'draft', 'scheduled', 'published'] as DevotionalStatus[]).map((s) => (
                        <button
                            key={s}
                            className={`tab${filter === s ? ' active' : ''}`}
                            onClick={() => setFilter(s)}
                        >
                            {s === 'all' ? 'All' : s.charAt(0).toUpperCase() + s.slice(1)}
                        </button>
                    ))}
                </div>

                {/* Devotionals List */}
                <div className="empty-state">
                    <div className="empty-state-icon">📖</div>
                    <div className="empty-state-title">No devotionals yet</div>
                    <div className="empty-state-text">
                        Create your first devotional to get started. You can write it from scratch or use a template.
                    </div>
                    <div style={{ display: 'flex', gap: 10, justifyContent: 'center' }}>
                        <Link href="/devotionals/new" className="btn btn-primary">
                            <span>✏️</span> Write Devotional
                        </Link>
                        <Link href="/templates" className="btn btn-secondary">
                            <span>📋</span> Browse Templates
                        </Link>
                    </div>
                </div>
            </div>
        </AdminLayout>
    );
}
